con:mockOperation.con:dispatchPath:
import com.eviware.soapui.support.XmlHolder
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlContext
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlValidator
import com.eviware.soapui.impl.wsdl.panels.mockoperation.WsdlMockRequestMessageExchange

synchronized(mockRequest.context.mockService){
def mockService = mockOperation.mockService

def wsdlcontext = context.mockService.getMockedInterfaces()[0].getDefinitionContext();
def validator = new WsdlValidator(wsdlcontext);
def msgExchange = new WsdlMockRequestMessageExchange(mockRequest, mockOperation); 
def errors = validator.assertRequest(msgExchange, false);

def msg = ""
if (errors.length > 0) {
	errors.each {
		log.error("Incoming request contains error ${it.toString()}")
		msg += "${it.toString()}\n"
	}
	context.validationMessages = msg
	return "SoapFault-Request"
}

def holder = new XmlHolder( mockRequest.requestContent )
holder.namespaces['soapenv'] = 'http://schemas.xmlsoap.org/soap/envelope/'
holder.namespaces['urn'] = 'urn:riv:itintegration:registry:1'
holder.namespaces['urn1'] = 'urn:riv:clinicalprocess:healthcond:description:GetCareDocumentationResponder:3'
holder.namespaces['urn2'] = 'urn:riv:clinicalprocess:healthcond:description:3'

def patientId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetCareDocumentation/urn1:patientId/urn2:extension')
def patientIdType = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetCareDocumentation/urn1:patientId/urn2:root')
def careGiverHSAId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetCareDocumentation/urn1:healthcareProvider/urn2:extension')
def careUnitHSAId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetCareDocumentation/urn1:careUnit/urn2:extension')
def sourceSystemHSAId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetCareDocumentation/urn1:sourceSystemId/urn2:extension')
def careContactId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetCareDocumentation/urn1:careContactId')

context.patientId = patientId
context.patientIdType = patientIdType
context.careGiverHSAId = careGiverHSAId ?: "careGiverHSAId"
context.careUnitHSAId = careUnitHSAId ?: "careUnitHSAId"
context.sourceSystemHSAId = sourceSystemHSAId ?: "sourceSystemHSAId"
context.careContactId = careContactId ?: "careContactId"

if (mockRequest.requestHeaders['x-mock-response'] != null){
	return mockRequest.requestHeaders['x-mock-response'][0]
}
else{
	//Kontrollera schema och schematron för request
	mh = new se.skl.rivta.tksupport.soapui.MockHelper(mockRequest, mockOperation, log)
	def validationErrors = mh.getSchemaErrorsInRequest() ?: mh.getSchematronErrorsInRequest("constraints.xml")
	if (validationErrors != null){
		context.validationMessages = validationErrors.toString()
		return "Response ERROR"
	}
}

}
